  deltaGoodWhen?: 'up' | 'down';
  footnote?: string;
  loading?: boolean;
}

const DELTA_GOOD = '#3f8600';
const DELTA_BAD = '#cf1322';

function DeltaBadge({
  delta,
  unit,
  goodWhen,
}: {
  delta: number;
  unit: string;
